static int qsearch(SearchInfo *si, int alpha, int beta) {
    Board *b = si->board;
    si->nodes++;

    if (si->stopped) return 0;
    check_time(si);
    if (si->stopped) return 0;

    if (b->ply > si->sel_depth) si->sel_depth = b->ply;

    /* Init PV length for this ply (must be before any early return) */
    si->pv_length[b->ply] = b->ply;

    if (b->ply >= MAX_PLY) return evaluate(b);

    /* Stand pat */
    int stand_pat = evaluate(b);
    if (stand_pat >= beta) return beta;
    if (stand_pat > alpha) alpha = stand_pat;

    MoveList ml;
    generate_captures(b, &ml);
    score_moves(b, &ml, MOVE_NONE, &si->sd, b->ply, MOVE_NONE);

    for (int i = 0; i < ml.count; i++) {
        pick_move(&ml, i);
        Move m = ml.moves[i];

        if (!is_move_legal(b, m)) continue;

        /* SEE pruning: skip captures with SEE < 0 */
        if (!move_is_promotion(m) && !see_ge(b, m, 0)) continue;

        /* Delta pruning: skip if capture can't raise alpha */
        if (!move_is_promotion(m)) {
            int captured = b->mailbox[move_to(m)];
            if (captured != NO_PIECE) {
                static const int piece_vals[] = { 100, 320, 330, 500, 900, 0 };
                int cap_val = piece_vals[piece_type_of(captured)];
                if (stand_pat + cap_val + 200 < alpha) continue;
            }
        }

        board_make_move(b, m);
        int score = -qsearch(si, -beta, -alpha);
        board_unmake_move(b);

        if (si->stopped) return 0;

        if (score > alpha) {
            alpha = score;
            if (score >= beta) return beta;
        }
    }

    return alpha;
}

