    if (stopped) return 0;
    nodes_++;
    check_time();
    if (stopped) return 0;

    if (ply >= MAX_PLY - 1)
        return Eval::evaluate(*pos_);

    int orig_alpha = alpha;
    bool in_check = pos_->is_in_check();

    // TT probe
    bool tt_hit;
    TTEntry* tte = TT.probe(pos_->key(), tt_hit);
    Move tt_move = tt_hit ? tte->move() : MOVE_NONE;
    int tt_value = tt_hit ? (int)tte->value : VALUE_NONE;

    // TT cutoff (not when in check — need to verify no mate)
    if (tt_hit && !in_check) {
        if ((tte->bound == BOUND_EXACT)
            || (tte->bound == BOUND_LOWER && tt_value >= beta)
            || (tte->bound == BOUND_UPPER && tt_value <= alpha))
            return tt_value;
    }

    int stand_pat;
    if (in_check) {
        stand_pat = -VALUE_INFINITE;
    } else {
        stand_pat = Eval::evaluate(*pos_);
        if (stand_pat >= beta) {
            tte->save(pos_->key(), stand_pat, BOUND_LOWER, 0, MOVE_NONE, stand_pat, TT.generation());
            return stand_pat;
        }
        if (stand_pat > alpha) alpha = stand_pat;
    }

    int best_score = stand_pat;
    Move best_qmove = MOVE_NONE;

    // In check: generate all legal moves (evasions)
    if (in_check) {
        MoveList pseudo;
        generate_moves(*pos_, pseudo);

        int move_count = 0;
        for (const auto& sm : pseudo) {
            if (!pos_->is_legal(sm.move)) continue;
            move_count++;

            StateInfo st;
            pos_->do_move(sm.move, st);
            int score = -quiescence(-beta, -alpha, ply + 1);
            pos_->undo_move(sm.move);

            if (score > best_score) {
                best_score = score;
                best_qmove = sm.move;
                if (score > alpha) {
                    alpha = score;
                    if (score >= beta) break;
                }
            }
        }

        if (move_count == 0)
            return -VALUE_MATE + ply;

        Bound bound = best_score >= beta ? BOUND_LOWER :
                      best_score > orig_alpha ? BOUND_EXACT : BOUND_UPPER;
        tte->save(pos_->key(), best_score, bound, 0, best_qmove, -VALUE_INFINITE, TT.generation());
        return best_score;
    }

    // Normal qsearch: captures only (with capture history for ordering)
    MovePicker mp(*pos_, tt_move, &capture_history_);
    Move move;

    while ((move = mp.next_move()) != MOVE_NONE) {
        // Delta pruning
        int captured_value = PieceValue[type_of(pos_->piece_on(move.to()))];
        if (move.type() == EN_PASSANT) captured_value = PieceValue[PAWN];
        if (move.type() == PROMOTION) captured_value += PieceValue[move.promotion_type()] - PieceValue[PAWN];
        if (stand_pat + captured_value + 200 < alpha)
            continue;

