        StateInfo st;
        pos_->do_move(move, st);
        int score = -quiescence(-beta, -alpha, ply + 1);
        pos_->undo_move(move);

        if (score > best_score) {
            best_score = score;
            best_qmove = move;
            if (score > alpha) {
                alpha = score;
                if (score >= beta) break;
            }
        }
    }

    // TT storage
    Bound bound = best_score >= beta ? BOUND_LOWER :
                  best_score > orig_alpha ? BOUND_EXACT : BOUND_UPPER;
    tte->save(pos_->key(), best_score, bound, 0, best_qmove, stand_pat, TT.generation());
