int Searcher::quiescence(Board &b, int alpha, int beta, int ply) {
  check_time();
  if (stop_) return alpha;
  nodes_++;

  const Color us = b.side_to_move();
  const bool in_check = b.in_check(us);

  if (ply >= MaxPly - 1) {
    return in_check ? (-MateScore + ply) : eval::evaluate(b);
  }

  int stand_pat = 0;
  if (!in_check) {
    stand_pat = eval::evaluate(b);
    if (stand_pat >= beta) return beta;
    if (stand_pat > alpha) alpha = stand_pat;
  }

  auto &pseudo = move_stack_[ply];
  movegen::generate_pseudo_legal(b, pseudo);

  std::vector<Move> *moves_ptr = &pseudo;
  if (!in_check) {
    auto &caps = qmove_stack_[ply];
    caps.clear();
    caps.reserve(pseudo.size());
    for (const Move &m : pseudo) {
      if (m.flags & MF_CAPTURE) caps.push_back(m);
      else if (m.flags & MF_PROMOTION) caps.push_back(m);
    }
    moves_ptr = &caps;
  }

  auto &moves = *moves_ptr;

  // Order moves: prioritize captures/promotions by MVV-LVA, then the rest.
  std::sort(moves.begin(), moves.end(), [&](const Move &a, const Move &c) {
    const bool capA = (a.flags & MF_CAPTURE) || (a.flags & MF_PROMOTION);
    const bool capC = (c.flags & MF_CAPTURE) || (c.flags & MF_PROMOTION);
    if (capA != capC) return capA > capC;
    if (!capA) return false;
    const Piece attA = b.piece_at(a.from);
    const Piece vicA = (a.flags & MF_EN_PASSANT) ? make_piece(!us, PieceType::Pawn) : b.piece_at(a.to);
    const Piece attC = b.piece_at(c.from);
    const Piece vicC = (c.flags & MF_EN_PASSANT) ? make_piece(!us, PieceType::Pawn) : b.piece_at(c.to);
    return mvv_lva(attA, vicA) > mvv_lva(attC, vicC);
  });

  int legal = 0;
  for (const Move &m : moves) {
    int optimistic_gain = 0;
    int see_score = 0;
    bool have_see = false;

    if (!in_check) {
      const PieceType attacker_from = type_of(b.piece_at(m.from));
      PieceType attacker_to = attacker_from;
      if (m.flags & MF_PROMOTION) attacker_to = static_cast<PieceType>(m.promo);

      if (m.flags & MF_CAPTURE) {
        PieceType victim = PieceType::None;
        if (m.flags & MF_EN_PASSANT) victim = PieceType::Pawn;
        else victim = type_of(b.piece_at(m.to));
        optimistic_gain += piece_value(victim);
      }
      if (m.flags & MF_PROMOTION) {
        optimistic_gain += piece_value(attacker_to) - piece_value(PieceType::Pawn);
      }

      const int attacker_value = piece_value(attacker_to);
      if ((m.flags & MF_CAPTURE) && optimistic_gain < attacker_value) {
        have_see = true;
        see_score = see(b, m);
      }
    }

    UndoState u;
    b.make_move(m, u);
    const bool illegal = b.is_square_attacked(b.king_square(us), b.side_to_move());
    if (illegal) {
      b.unmake_move(m, u);
      continue;
    }

    const bool gives_check = b.in_check(b.side_to_move());
    if (!in_check && !gives_check) {
      // Delta pruning: if even the optimistic material swing can't raise alpha, skip.
      constexpr int kDeltaMargin = 120;
      if (stand_pat + optimistic_gain + kDeltaMargin < alpha) {
        b.unmake_move(m, u);
        continue;
      }

      // SEE pruning: skip clearly losing captures unless they give check.
      if (have_see && see_score < 0) {
        b.unmake_move(m, u);
        continue;
      }
    }
    legal++;
    const int score = -quiescence(b, -beta, -alpha, ply + 1);
    b.unmake_move(m, u);
    if (stop_) return alpha;
    if (score >= beta) return beta;
    if (score > alpha) alpha = score;
  }

  if (in_check && legal == 0) {
    return -MateScore + ply;
  }
  return alpha;
}

