fn quiescence(&mut self, mut alpha: i32, beta: i32, ply: usize) -> i32 {
    self.nodes += 1;
    self.check_time();
    if self.timer.should_stop() {
        return 0;
    }

    if ply >= MAX_PLY - 1 {
        return self.eval();
    }

    let is_pv = beta - alpha > 1;
    let hash = self.board.hash;

    // TT probe in qsearch
    if let Some(entry) = self.tt.probe(hash) {
        let tt_score = self.score_from_tt(entry.score as i32, ply);
        if !is_pv {
            match entry.flag() {
                TTFlag::Exact => return tt_score,
                TTFlag::LowerBound if tt_score >= beta => return tt_score,
                TTFlag::UpperBound if tt_score <= alpha => return tt_score,
                _ => {}
            }
        }
    }

    // Stand pat
    let stand_pat = self.eval();

    if stand_pat >= beta {
        return stand_pat;
    }

    // Delta pruning: if we can't possibly raise alpha even with the best capture
    if stand_pat + 1000 < alpha {
        return stand_pat;
    }

    if stand_pat > alpha {
        alpha = stand_pat;
    }

    let original_alpha = alpha;
    let mut best_score = stand_pat;
    let mut best_move = Move::NONE;

    let mut moves = self.board.gen_captures();
    movepick::score_captures(&self.board, &mut moves);

    for i in 0..moves.len() {
        let sm = moves.pick_move(i);
        let mv = sm.mv;

        // SEE pruning: skip bad captures
        if !self.board.see(mv, 0) {
            continue;
        }

        self.board.make_move(mv);
        let score = -self.quiescence(-beta, -alpha, ply + 1);
        self.board.unmake_move(mv);

        if self.timer.should_stop() {
            return 0;
        }

        if score > best_score {
            best_score = score;
            best_move = mv;
            if score > alpha {
                alpha = score;
                if score >= beta {
                    break;
                }
            }
        }
    }

    // Store in TT
    let flag = if best_score >= beta {
        TTFlag::LowerBound
    } else if best_score > original_alpha {
        TTFlag::Exact
    } else {
        TTFlag::UpperBound
    };
    self.tt.store(
        hash,
        best_move,
        self.score_to_tt(best_score, ply) as i16,
        0,
        flag,
    );

    best_score
}

