  const bool in_check_now = in_check(pos, pos.stm, ss.cfg);
  const SearchPolicy& sp = ss.cfg.search_policy;

  int stand = -INF;
  if (!in_check_now) {
    stand = evaluate(pos);
    if (stand >= beta) {
      return beta;
    }
    if (stand > alpha) {
      alpha = stand;
    }
  }

